((SELECT id FROM checklists WHERE title = 'Inflatable Safety Tip Checklist' ORDER BY created_at DESC LIMIT 1), 'Check the weather forecast before the event', 1),
((SELECT id FROM checklists WHERE title = 'Inflatable Safety Tip Checklist' ORDER BY created_at DESC LIMIT 1), 'Monitor wind speeds throughout the day', 2),
((SELECT id FROM checklists WHERE title = 'Inflatable Safety Tip Checklist' ORDER BY created_at DESC LIMIT 1), 'Watch for sudden weather changes (lightning, heavy rain, hail)', 3),
((SELECT id FROM checklists WHERE title = 'Inflatable Safety Tip Checklist' ORDER BY created_at DESC LIMIT 1), 'Communicate weather policy to team and clients', 4),
((SELECT id FROM checklists WHERE title = 'Inflatable Safety Tip Checklist' ORDER BY created_at DESC LIMIT 1), 'Inspect setup area for debris, holes, slopes, and overhead hazards', 5),
((SELECT id FROM checklists WHERE title = 'Inflatable Safety Tip Checklist' ORDER BY created_at DESC LIMIT 1), 'Ensure adequate clearance on all sides (minimum 6 feet)', 6),
((SELECT id FROM checklists WHERE title = 'Inflatable Safety Tip Checklist' ORDER BY created_at DESC LIMIT 1), 'Place ground tarps or mats under the inflatable', 7),
((SELECT id FROM checklists WHERE title = 'Inflatable Safety Tip Checklist' ORDER BY created_at DESC LIMIT 1), 'Verify power source is adequate and cords are safely routed', 8),
((SELECT id FROM checklists WHERE title = 'Inflatable Safety Tip Checklist' ORDER BY created_at DESC LIMIT 1), 'Confirm blower is securely attached and tube is properly sealed', 9),
