((SELECT id FROM checklists WHERE title = 'Inflatable Safety Tip Checklist' ORDER BY created_at DESC LIMIT 1), 'Verify all D-rings, straps, and buckles are intact and secure', 13),
((SELECT id FROM checklists WHERE title = 'Inflatable Safety Tip Checklist' ORDER BY created_at DESC LIMIT 1), 'Post visible safety rules signage at the event', 14),
((SELECT id FROM checklists WHERE title = 'Inflatable Safety Tip Checklist' ORDER BY created_at DESC LIMIT 1), 'Review safety rules with client and attendees', 15),
((SELECT id FROM checklists WHERE title = 'Inflatable Safety Tip Checklist' ORDER BY created_at DESC LIMIT 1), 'Have clients sign safety agreement or waiver', 16),
((SELECT id FROM checklists WHERE title = 'Inflatable Safety Tip Checklist' ORDER BY created_at DESC LIMIT 1), 'Ensure adult supervisor is present at all times', 17);
